command:example.dev:code:
# Streaming output
Invoke-AnthropicMessage -Messages @(
    New-AnthropicMessage -Role 'user' -Content 'Write a haiku'
) -Stream | ForEach-Object {
    if ($_.type -eq 'content_block_delta') {
        Write-Host $_.delta.text -NoNewline
    }
}

# In a tool use loop with shell access
$toolUse = $response.content | Where-Object { $_.type -eq 'tool_use' }
$result = Invoke-AnthropicStandardTool -ToolUse $toolUse -AllowShell

# Use in a message with text
$response = Invoke-AnthropicMessage -Messages @(
    @{
        role = 'user'
        content = @(
            @{ type = 'text'; text = 'What is in this image?' }
            (New-AnthropicImageContent -Path './photo.jpg')
        )
    }
) -Model 'llava'

$content = @(
    @{ type = 'text'; text = 'What is in this image?' }
    (New-AnthropicImageContent -Path './image.png')
)
New-AnthropicMessage -Role 'user' -Content $content
# Creates a message with text and image content

$tool = New-AnthropicTool -Name 'get_weather' -Description 'Get weather for a location' -InputSchema @{
    type = 'object'
    properties = @{
        location = @{ type = 'string'; description = 'City name' }
        unit = @{ type = 'string'; enum = @('celsius', 'fahrenheit') }
    }
    required = @('location')
}

# Simple tool with no parameters
$tool = New-AnthropicTool -Name 'get_time' -Description 'Get current time' -InputSchema @{
    type = 'object'
    properties = @{}
}

# Register multiple functions as tools
$tools = 'Get-Process', 'Get-Service', 'Get-Date' | ForEach-Object {
    New-AnthropicToolFromCommand -CommandName $_
}

# Get tool use from response $toolUse = $response.content | Where-Object { $_.type -eq 'tool_use' }
# Execute tool and get result $result = Get-Weather -Location $toolUse.input.location
# Create tool result message $toolResult = New-AnthropicToolResult -ToolUseId $toolUse.id -Content $result

Set-AnthropicRouterConfig -Models @{
    Default = 'llama3.1-8k'
    Code    = 'qwen3-coder-8k'
    Vision  = 'llama3.2-vision:11b'
}

Set-AnthropicRouterConfig -Models @{
    Default = 'llama3.1-8k'
    Code    = 'qwen3-coder-8k'
} -LogPath './router.log' -LogToConsole
